/**
 * 使用例のソース(自動生成・手で編集しない)。
 *
 * **実行時にファイルを読まない**ため、ビルド時に固めてある。
 * `process.cwd()` は Amplify の SSR で想定と違う場所を指すので、
 * ファイル I/O に頼ると画面が壊れる。
 *
 * 再生成: `node tools/gen-example-sources.mjs`(`pnpm gen:all` に含まれる)
 *
 * @packageDocumentation
 */

/** 使用例の名前 → ソースコード。 */
export const EXAMPLE_SOURCES: Record<string, string> = {
  "accounting-sync": "import { syncJournals, summarizeSync, type Sender, type JournalEntry } from \"@platform/accounting\";\nimport { buildManualJournal } from \"@platform/freee\";\n\n/** freee へ送る Sender を作る(companyId と送信関数を渡す)。 */\nexport function createFreeeSender(\n  companyId: number,\n  post: (journal: ReturnType<typeof buildManualJournal>) => Promise<{ ok: boolean; error?: string }>,\n): Sender {\n  return async (payload) => {\n    const journal = buildManualJournal({\n      companyId,\n      issueDate: payload.date,\n      details: payload.details.map((d) => ({\n        entrySide: d.entrySide,\n        accountItemId: d.accountItemId,\n        amount: d.amount,\n        // freee は税区分コードが必須。0 = 対象外(仕訳の内容に応じて変える)\n        taxCode: 0,\n      })),\n    });\n    return post(journal);\n  };\n}\n\n/** 仕訳を freee へバッチ送信し、結果サマリを返す。 */\nexport async function runSyncBatch(\n  entries: JournalEntry[],\n  options: { companyId: number; accountItemIds: Record<string, number>; alreadySent: Set<string>; post: (j: ReturnType<typeof buildManualJournal>) => Promise<{ ok: boolean; error?: string }> },\n) {\n  const send = createFreeeSender(options.companyId, options.post);\n  const result = await syncJournals(entries, { send, accountItemIds: options.accountItemIds, alreadySent: options.alreadySent });\n  return { ...result, summary: summarizeSync(result.results) };\n}",
  "accounting-sync-sync-job": "import { createGuardedJob } from \"@platform/cron\";\nimport { syncJournals, summarizeSync, type Sender, type JournalEntry } from \"@platform/accounting\";\n\n/** 送信済みキーの永続化ストア(DB/Redis を注入)。 */\nexport interface SentStore {\n  loadSent(): Promise<Set<string>>;\n  markSent(keys: string[]): Promise<void>;\n}\n\n/** 送信バッチのガード付きジョブを作る。 */\nexport function createSyncJob(options: {\n  loadEntries: () => Promise<JournalEntry[]>;\n  send: Sender;\n  accountItemIds: Record<string, number>;\n  store: SentStore;\n  onResult?: (summary: { sent: number; skipped: number; failed: number }) => void;\n}) {\n  return createGuardedJob({\n    name: \"accounting-sync\",\n    preventOverlap: true,\n    handler: async () => {\n      const entries = await options.loadEntries();\n      const alreadySent = await options.store.loadSent();\n      const result = await syncJournals(entries, { send: options.send, accountItemIds: options.accountItemIds, alreadySent });\n      if (result.sent.length > 0) await options.store.markSent(result.sent);\n      options.onResult?.(summarizeSync(result.results));\n    },\n  });\n}",
  "blueprint-integration": "import { applyTransition, evaluateTransition, type Blueprint } from \"@platform/blueprint\";\nimport { routeByAmount, startWorkflow, approve, type AmountTier, type WorkflowState, type Actor } from \"@platform/workflow\";\n\n/** 経費レコード(承認ワークフローの状態を内包)。 */\nexport interface Expense extends Record<string, unknown> {\n  state: \"draft\" | \"submitted\" | \"approved\" | \"rejected\";\n  amount: number;\n  purpose?: string;\n  /** 進行中の承認ワークフロー状態。 */\n  approval?: WorkflowState;\n}\n\n/** 金額帯ごとの承認段数(少額は課長のみ、高額は課長→部長→役員)。 */\nexport const APPROVAL_TIERS: AmountTier[] = [\n  { under: 30000, steps: [{ name: \"課長承認\", approverRole: \"manager\" }] },\n  { under: 100000, steps: [{ name: \"課長承認\", approverRole: \"manager\" }, { name: \"部長承認\", approverRole: \"director\" }] },\n  { steps: [{ name: \"課長承認\", approverRole: \"manager\" }, { name: \"部長承認\", approverRole: \"director\" }, { name: \"役員承認\", approverRole: \"executive\" }] },\n];\n\n/** 経費の全体プロセス(承認は workflow に委譲)。 */\nexport const expenseBlueprint: Blueprint<Expense[\"state\"], Expense> = {\n  initial: \"draft\",\n  states: [\"draft\", \"submitted\", \"approved\", \"rejected\"],\n  final: [\"approved\", \"rejected\"],\n  transitions: [\n    { from: \"draft\", to: \"submitted\", name: \"提出\", requiredFields: [\"amount\", \"purpose\"], actions: [\"startApproval\"] },\n    { from: \"submitted\", to: \"approved\", name: \"承認完了\", condition: (e) => e.approval?.status === \"approved\", actions: [\"postJournal\"] },\n    { from: \"submitted\", to: \"rejected\", name: \"却下\", condition: (e) => e.approval?.status === \"rejected\" },\n  ],\n};\n\n/** 提出: ブループリントで submitted にし、金額に応じた承認ワークフローを開始する。 */\nexport function submit(expense: Expense): { ok: boolean; expense: Expense; errors: string[] } {\n  const t = applyTransition(expenseBlueprint, expense, \"提出\");\n  if (!t.ok) return { ok: false, expense, errors: t.errors };\n  const def = routeByAmount(expense.amount, APPROVAL_TIERS);\n  return { ok: true, expense: { ...t.record, approval: startWorkflow(def) }, errors: [] };\n}\n\n/** 承認: workflow の現在ステップを承認し、全段完了ならブループリントを「承認完了」へ進める。 */\nexport function approveStep(expense: Expense, actor: Actor): { ok: boolean; expense: Expense; errors: string[] } {\n  if (!expense.approval) return { ok: false, expense, errors: [\"承認ワークフローが開始されていません\"] };\n  const def = routeByAmount(expense.amount, APPROVAL_TIERS);\n  const result = approve(def, expense.approval, actor);\n  if (!result.ok) return { ok: false, expense, errors: [result.error.message] };\n\n  const next: Expense = { ...expense, approval: result.value };\n  // 全段承認されたらブループリントを前進(仕訳起票アクションが発火)\n  if (result.value.status === \"approved\") {\n    const done = applyTransition(expenseBlueprint, next, \"承認完了\");\n    if (done.ok) return { ok: true, expense: done.record, errors: [] };\n  }\n  return { ok: true, expense: next, errors: [] };\n}\n\n/** 現在の承認段の残り承認者ロール(次に承認すべきロール)を返す。 */\nexport function pendingApprovalRole(expense: Expense): string | null {\n  if (!expense.approval || expense.approval.status !== \"pending\") return null;\n  const def = routeByAmount(expense.amount, APPROVAL_TIERS);\n  return def.steps[expense.approval.currentStep]?.approverRole ?? null;\n}",
  "blueprint-workflow": "import { renderTemplate } from \"@platform/notify\";\nimport { pendingApprovalRole, type Expense } from \"./blueprint-integration\";\n\n/** 通知メッセージ(宛先ロールと本文)。 */\nexport interface ApprovalNotification {\n  /** 宛先(ロール。実送信時はロール→ユーザーに解決)。 */\n  toRole: string;\n  subject: string;\n  body: string;\n}\n\nconst APPROVAL_REQUEST = \"経費申請「{{purpose}}」({{amount}}円)の{{role}}承認をお願いします。\";\nconst APPROVED = \"経費申請「{{purpose}}」({{amount}}円)が承認されました。\";\nconst REJECTED = \"経費申請「{{purpose}}」({{amount}}円)は却下されました。\";\n\n/** 提出/承認後の状態から、次に送るべき通知を決める。無ければ null。 */\nexport function notificationFor(expense: Expense, requesterRole = \"applicant\"): ApprovalNotification | null {\n  const status = expense.approval?.status;\n  if (status === \"pending\") {\n    const role = pendingApprovalRole(expense);\n    if (!role) return null;\n    return {\n      toRole: role,\n      subject: \"承認依頼\",\n      body: renderTemplate(APPROVAL_REQUEST, { purpose: expense.purpose ?? \"\", amount: expense.amount, role }),\n    };\n  }\n  if (expense.state === \"approved\") {\n    return { toRole: requesterRole, subject: \"承認完了\", body: renderTemplate(APPROVED, { purpose: expense.purpose ?? \"\", amount: expense.amount }) };\n  }\n  if (expense.state === \"rejected\") {\n    return { toRole: requesterRole, subject: \"却下\", body: renderTemplate(REJECTED, { purpose: expense.purpose ?? \"\", amount: expense.amount }) };\n  }\n  return null;\n}",
  "board-threads": "import { type Thread, type Post, type Reaction, countReactions, userReactions, summarize, sortThreads, type ThreadSummary } from \"@platform/board\";\n\n/** PostCard 用のリアクション表示。 */\nexport interface ReactionView {\n  kind: string;\n  count: number;\n  reacted: boolean;\n}\n\n/** PostCard 用の投稿ビュー。 */\nexport interface PostView {\n  id: string;\n  authorName: string;\n  body: string;\n  timestamp: string;\n  edited: boolean;\n  reactions: ReactionView[];\n}\n\n/** 投稿を、自分のリアクション状態つきで PostCard 用に整形する。 */\nexport function toPostView(post: Post, reactions: Reaction[], meId: string, nameOf: (userId: string) => string): PostView {\n  const counts = countReactions(reactions, post.id);\n  const mine = new Set(userReactions(reactions, post.id, meId));\n  const reactionViews: ReactionView[] = Object.entries(counts).map(([kind, count]) => ({ kind, count, reacted: mine.has(kind) }));\n  return { id: post.id, authorName: nameOf(post.authorId), body: post.body, timestamp: post.createdAt.slice(0, 16).replace(\"T\", \" \"), edited: Boolean(post.editedAt), reactions: reactionViews };\n}\n\n/** スレッド一覧を要約し、ピン→最新順に並べた要約を返す。 */\nexport function toThreadList(threads: Thread[], postsByThread: Record<string, Post[]>): ThreadSummary[] {\n  const summaries = threads.map((t) => summarize(t, postsByThread[t.id] ?? []));\n  return sortThreads(summaries);\n}",
  "board-threads-board-view": "import { type Thread, type Post, type Reaction, countReactions, userReactions, summarize, sortThreads, type ThreadSummary } from \"@platform/board\";\n\n/** PostCard 用のリアクション表示。 */\nexport interface ReactionView {\n  kind: string;\n  count: number;\n  reacted: boolean;\n}\n\n/** PostCard 用の投稿ビュー。 */\nexport interface PostView {\n  id: string;\n  authorName: string;\n  body: string;\n  timestamp: string;\n  edited: boolean;\n  reactions: ReactionView[];\n}\n\n/** 投稿を、自分のリアクション状態つきで PostCard 用に整形する。 */\nexport function toPostView(post: Post, reactions: Reaction[], meId: string, nameOf: (userId: string) => string): PostView {\n  const counts = countReactions(reactions, post.id);\n  const mine = new Set(userReactions(reactions, post.id, meId));\n  const reactionViews: ReactionView[] = Object.entries(counts).map(([kind, count]) => ({ kind, count, reacted: mine.has(kind) }));\n  return { id: post.id, authorName: nameOf(post.authorId), body: post.body, timestamp: post.createdAt.slice(0, 16).replace(\"T\", \" \"), edited: Boolean(post.editedAt), reactions: reactionViews };\n}\n\n/** スレッド一覧を要約し、ピン→最新順に並べた要約を返す。 */\nexport function toThreadList(threads: Thread[], postsByThread: Record<string, Post[]>): ThreadSummary[] {\n  const summaries = threads.map((t) => summarize(t, postsByThread[t.id] ?? []));\n  return sortThreads(summaries);\n}",
  "cast-site": "import {\n  type Cast, type RankedCast,\n  activeCasts, castsByTag, featuredCasts, newcomers, tagCounts,\n  rankCasts, profileItems, profileCompleteness, type ProfileField,\n} from \"@platform/cast\";\nimport {\n  accountsFromUrls, accountLinks, latestPerPlatform, type SocialPost,\n} from \"@platform/social\";\nimport {\n  generateSlots, staffAvailableSlots, reminderSchedule, isWithinBookingWindow,\n  canCancel, BOOKING_STATUS_LABELS, type Shift, type BookingInterval, type TimeRange,\n} from \"@platform/booking\";\nimport { buildMeta, type MetaResult } from \"@platform/seo\";\n\n/** トップページのデータ。 */\nexport interface HomePageData<T extends RankedCast> {\n  featured: T[];\n  newcomers: T[];\n  ranking: { rank: number; cast: T; score: number }[];\n  tags: { tag: string; count: number }[];\n}\n\n/** トップページ: 注目・新人・口コミランキング・タグ一覧をまとめる。 */\nexport function buildHomePage<T extends RankedCast>(casts: T[], now?: Date): HomePageData<T> {\n  return {\n    featured: featuredCasts(casts, 6),\n    newcomers: newcomers(casts, 30, now),\n    ranking: rankCasts(casts, { minCount: 10, limit: 10 }),\n    tags: tagCounts(casts),\n  };\n}\n\n/** キャスト個別ページのデータ。 */\nexport interface CastPageData {\n  profile: { label: string; value: string }[];\n  completeness: number;\n  socialLinks: { platform: string; label: string; url: string }[];\n  latestPosts: SocialPost[];\n  meta: MetaResult;\n}\n\n/** キャスト個別ページ: プロフィール + SNS リンク + 各SNS最新投稿 + 公開用メタ。 */\nexport function buildCastPage(\n  cast: Cast,\n  input: { socialUrls: string[]; posts: SocialPost[]; fields: ProfileField[]; baseUrl: string },\n): CastPageData {\n  const accounts = accountsFromUrls(input.socialUrls);\n  const bio = typeof cast.bio === \"string\" ? cast.bio : `${cast.name}のプロフィール`;\n  return {\n    profile: profileItems(cast, input.fields),\n    completeness: profileCompleteness(cast, input.fields),\n    socialLinks: accountLinks(accounts),\n    latestPosts: latestPerPlatform(input.posts),\n    // 公開ページなので visibility: \"public\"(社内ツールなら \"internal\" で検索避け)\n    meta: buildMeta({ title: cast.name, description: bio, canonical: `${input.baseUrl}/cast/${cast.id}`, visibility: \"public\" }),\n  };\n}\n\n/** 指名予約の空き枠: 店のスロット × キャストのシフト − そのキャストの予約。 */\nexport function buildCastAvailability(input: {\n  openingHours: TimeRange[];\n  shifts: Shift[];\n  bookings: BookingInterval[];\n  slotMinutes: number;\n}): { start: string; end: string }[] {\n  const slots = generateSlots(input.openingHours, { slotMinutes: input.slotMinutes });\n  return staffAvailableSlots(slots, input.shifts, input.bookings);\n}\n\n/** 予約リクエストの検証結果。 */\nexport interface BookingValidation {\n  ok: boolean;\n  reason?: string;\n}\n\n/** 予約可否の検証(受付期間 + キャンセル可否の情報)。 */\nexport function validateBookingRequest(bookingAt: string, now?: Date): BookingValidation {\n  const check = isWithinBookingWindow(bookingAt, { minLeadMinutes: 60, maxAdvanceDays: 30 }, now);\n  return { ok: check.ok, reason: check.reason };\n}\n\n/** 予約確定時のリマインダー設定(前日メール + 2時間前SMS)。 */\nexport function scheduleBookingReminders(bookingAt: string) {\n  return reminderSchedule(bookingAt, [\n    { beforeMinutes: 1440, channel: \"email\" },\n    { beforeMinutes: 120, channel: \"sms\" },\n  ]);\n}\n\n/** 予約ステータスの日本語ラベル(表示用の再エクスポート)。 */\nexport const statusLabel = BOOKING_STATUS_LABELS;\n\n/** キャンセル可能かの判定(24時間前まで)。 */\nexport function canCancelBooking(bookingAt: string, now?: Date): boolean {\n  return canCancel(bookingAt, 1440, now);\n}",
  "chat-room": "import { groupByDate, type ChatMessage } from \"@platform/chat\";\n\n/** UI 表示用メッセージ。 */\nexport interface DisplayMessage {\n  id: string;\n  text: string;\n  authorName?: string;\n  timestamp?: string;\n  own?: boolean;\n  edited?: boolean;\n}\n\n/** 日付グループ。 */\nexport interface MessageGroup {\n  date: string;\n  messages: DisplayMessage[];\n}\n\n/** 時刻 \"HH:MM\"(UTC 表記の簡易版)。 */\nfunction hhmm(iso: string): string {\n  return iso.slice(11, 16);\n}\n\n/** メッセージ配列を、自分視点・表示名解決つきで UI 用グループに変換する。 */\nexport function toMessageGroups(messages: ChatMessage[], meId: string, nameOf: (userId: string) => string): MessageGroup[] {\n  return groupByDate(messages).map((g) => ({\n    date: g.date,\n    messages: g.messages.map((m) => ({\n      id: m.id,\n      text: m.text,\n      authorName: nameOf(m.senderId),\n      timestamp: hhmm(m.at),\n      own: m.senderId === meId,\n      edited: Boolean(m.editedAt),\n    })),\n  }));\n}",
  "chat-room-room-session": "import { createMessage, type ChatMessage } from \"@platform/chat\";\nimport { type BroadcastHub } from \"@platform/realtime\";\n\n/** ルームのチャネル名。 */\nexport function roomChannel(roomId: string): string {\n  return `room:${roomId}`;\n}\n\n/** 送信結果。 */\nexport type SendResult = { ok: true; message: ChatMessage } | { ok: false; error: string };\n\n/**\n * メッセージを検証して配信する。検証 NG なら publish せずエラーを返す。\n */\nexport async function sendMessage(hub: BroadcastHub, input: { id: string; roomId: string; senderId: string; text: string; at?: string }): Promise<SendResult> {\n  const created = createMessage(input);\n  if (!created.ok) return created;\n  await hub.publish(roomChannel(input.roomId), created.message);\n  return { ok: true, message: created.message };\n}\n\n/**\n * ルームを購読し、受信メッセージを onMessage に渡す。返り値で購読解除。\n */\nexport async function joinRoom(\n  hub: BroadcastHub,\n  roomId: string,\n  connectionId: string,\n  onMessage: (message: ChatMessage) => void,\n): Promise<() => Promise<void>> {\n  const channel = roomChannel(roomId);\n  await hub.subscribe(channel, connectionId, (data: string) => {\n    onMessage(JSON.parse(data) as ChatMessage);\n  });\n  return () => hub.unsubscribe(channel, connectionId);\n}",
  "chat-room-view": "import { groupByDate, type ChatMessage } from \"@platform/chat\";\n\n/** UI 表示用メッセージ。 */\nexport interface DisplayMessage {\n  id: string;\n  text: string;\n  authorName?: string;\n  timestamp?: string;\n  own?: boolean;\n  edited?: boolean;\n}\n\n/** 日付グループ。 */\nexport interface MessageGroup {\n  date: string;\n  messages: DisplayMessage[];\n}\n\n/** 時刻 \"HH:MM\"(UTC 表記の簡易版)。 */\nfunction hhmm(iso: string): string {\n  return iso.slice(11, 16);\n}\n\n/** メッセージ配列を、自分視点・表示名解決つきで UI 用グループに変換する。 */\nexport function toMessageGroups(messages: ChatMessage[], meId: string, nameOf: (userId: string) => string): MessageGroup[] {\n  return groupByDate(messages).map((g) => ({\n    date: g.date,\n    messages: g.messages.map((m) => ({\n      id: m.id,\n      text: m.text,\n      authorName: nameOf(m.senderId),\n      timestamp: hhmm(m.at),\n      own: m.senderId === meId,\n      edited: Boolean(m.editedAt),\n    })),\n  }));\n}",
  "data-console": "\"use client\";\n/**\n * データ一覧の完成テンプレート(検索 + 外部フィルタ + ソート + ページャ)。\n * @platform/ui の queryRows(検索/ソート/ページの純パイプライン)+ SearchInput + Pagination + EmptyState を束ねる。\n * DataTable の組み込み検索では足りない「状態フィルタ」等を外部で足す構成の見本。\n * @packageDocumentation\n */\nimport * as React from \"react\";\nimport { queryRows, SearchInput, Pagination, EmptyState, Button, type TableQuery } from \"@platform/ui\";\n\n/** 予約行(サンプル)。 */\nexport interface BookingRow {\n  id: string;\n  customer: string;\n  cast: string;\n  status: \"requested\" | \"confirmed\" | \"completed\" | \"cancelled\";\n  date: string;\n  [k: string]: unknown;\n}\n\nconst STATUS_LABELS: Record<BookingRow[\"status\"] | \"all\", string> = {\n  all: \"すべて\",\n  requested: \"申込\",\n  confirmed: \"確定\",\n  completed: \"完了\",\n  cancelled: \"キャンセル\",\n};\n\nconst PAGE_SIZE = 10;\n\n/** {@link DataConsole} の props。 */\nexport interface DataConsoleProps {\n  rows: BookingRow[];\n}\n\n/** 検索 + フィルタ + ソート + ページャのデータ一覧テンプレート。 */\nexport function DataConsole({ rows }: DataConsoleProps) {\n  const [search, setSearch] = React.useState(\"\");\n  const [status, setStatus] = React.useState<BookingRow[\"status\"] | \"all\">(\"all\");\n  const [sortKey, setSortKey] = React.useState<string>(\"date\");\n  const [sortDir, setSortDir] = React.useState<\"asc\" | \"desc\">(\"desc\");\n  const [page, setPage] = React.useState(1);\n\n  // 外部フィルタ(状態)を先に適用\n  const filtered = React.useMemo(\n    () => (status === \"all\" ? rows : rows.filter((r) => r.status === status)),\n    [rows, status],\n  );\n\n  // 検索・ソート・ページングは queryRows(純ロジック)に任せる\n  const query: TableQuery = { search, searchKeys: [\"customer\", \"cast\"], sortKey, sortDir, page, pageSize: PAGE_SIZE };\n  const result = React.useMemo(() => queryRows(filtered, query), [filtered, search, sortKey, sortDir, page]);\n\n  // フィルタ/検索変更時はページを先頭へ\n  React.useEffect(() => { setPage(1); }, [search, status]);\n\n  function toggleSort(key: string) {\n    if (sortKey === key) setSortDir((d) => (d === \"asc\" ? \"desc\" : \"asc\"));\n    else { setSortKey(key); setSortDir(\"asc\"); }\n  }\n\n  const columns: { key: keyof BookingRow & string; label: string; sortable?: boolean }[] = [\n    { key: \"customer\", label: \"お客様\", sortable: true },\n    { key: \"cast\", label: \"キャスト\", sortable: true },\n    { key: \"status\", label: \"状態\" },\n    { key: \"date\", label: \"日時\", sortable: true },\n  ];\n\n  return (\n    <div className=\"flex flex-col gap-4\">\n      <div className=\"flex flex-wrap items-center gap-3\">\n        <SearchInput value={search} onValueChange={setSearch} placeholder=\"お客様・キャストで検索\" className=\"w-64\" />\n        <div className=\"flex gap-1\">\n          {(Object.keys(STATUS_LABELS) as (BookingRow[\"status\"] | \"all\")[]).map((s) => (\n            <Button key={s} variant={status === s ? \"primary\" : \"secondary\"} size=\"sm\" onClick={() => setStatus(s)}>\n              {STATUS_LABELS[s]}\n            </Button>\n          ))}\n        </div>\n        <span className=\"ml-auto text-sm text-[var(--color-muted)]\">{result.total} 件</span>\n      </div>\n\n      {result.total === 0 ? (\n        <EmptyState title=\"該当する予約がありません\" description=\"検索条件やフィルタを変えてみてください\" />\n      ) : (\n        <>\n          <table className=\"w-full border-collapse text-sm\">\n            <thead>\n              <tr className=\"border-b border-[var(--color-border)] text-left text-[var(--color-muted)]\">\n                {columns.map((col) => (\n                  <th key={col.key} className=\"px-3 py-2 font-medium\">\n                    {col.sortable ? (\n                      <button type=\"button\" onClick={() => toggleSort(col.key)} className=\"inline-flex items-center gap-1 hover:text-[var(--color-fg)]\">\n                        {col.label}\n                        {sortKey === col.key && <span aria-hidden=\"true\">{sortDir === \"asc\" ? \"▲\" : \"▼\"}</span>}\n                      </button>\n                    ) : col.label}\n                  </th>\n                ))}\n              </tr>\n            </thead>\n            <tbody>\n              {result.rows.map((row) => (\n                <tr key={row.id} className=\"border-b border-[var(--color-border)]\">\n                  <td className=\"px-3 py-2\">{row.customer}</td>\n                  <td className=\"px-3 py-2\">{row.cast}</td>\n                  <td className=\"px-3 py-2\">{STATUS_LABELS[row.status]}</td>\n                  <td className=\"px-3 py-2\">{row.date}</td>\n                </tr>\n              ))}\n            </tbody>\n          </table>\n\n          <Pagination page={result.page} totalPages={result.pageCount} onPageChange={setPage} />\n        </>\n      )}\n    </div>\n  );\n}",
  "loadtest-scenarios": "import type { Scenario, ScenarioStep, RequestFn, RequestOutcome } from \"@platform/loadtest\";\n\n/** HTTP リクエストを組み立てるための最小の依存。テストではモックを渡す。 */\nexport interface HttpDeps {\n  /** ベース URL(例: http://localhost:3000)。 */\n  baseUrl: string;\n  /** fetch 実装(既定: グローバル fetch)。テストで差し替える。 */\n  fetchImpl?: typeof fetch;\n  /** 認証済みリクエストにする Cookie(例: \"session=xxx\")。 */\n  cookie?: string;\n  /** 時刻の取得(テスト注入用)。 */\n  now?: () => number;\n}\n\n/**\n * URL とメソッドから RequestFn を作る。所要時間を測り、ok/status を返す。\n * 失敗しても例外にせず `{ ok: false }` を返す(負荷テストは止めない)。\n */\nexport function buildHttpStep(deps: HttpDeps) {\n  const fetchImpl = deps.fetchImpl ?? globalThis.fetch;\n  const now = deps.now ?? Date.now;\n  return (path: string, init?: RequestInit): RequestFn =>\n    async (): Promise<RequestOutcome> => {\n      const t0 = now();\n      try {\n        const headers: Record<string, string> = { ...(init?.headers as Record<string, string> | undefined) };\n        if (deps.cookie) headers.cookie = deps.cookie;\n        const res = await fetchImpl(`${deps.baseUrl}${path}`, { ...init, headers });\n        return { ok: res.ok, status: res.status };\n      } catch (e) {\n        return { ok: false, error: e instanceof Error ? e.message : String(e) };\n      }\n    };\n}\n\n/**\n * 【朝の一斉打刻】9:00 前後に全社員が同時に出勤打刻する。\n *\n * 最も過酷な瞬間。**書き込みが一点に集中**するため、DB のロック競合が出やすい。\n * ランプアップ無し(rampUpMs: 0)で撃つと、実際の「9:00 きっかり」に近い形になる。\n *\n * 想定: 打刻 8 割 / 自分の勤怠確認 2 割(打刻後に確認する人)\n */\nexport function morningRush(step: ReturnType<typeof buildHttpStep>): Scenario {\n  return {\n    steps: [\n      { name: \"打刻(出勤)\", weight: 8, request: step(\"/api/attendance\", { method: \"POST\", body: JSON.stringify({ type: \"clockIn\" }) }) },\n      { name: \"自分の勤怠確認\", weight: 2, request: step(\"/api/attendance\") },\n    ],\n  };\n}\n\n/**\n * 【月初の経費申請ラッシュ】月初 3 日間に経費申請が集中する。\n *\n * 打刻と違い**読み書きが混ざる**。一覧の取得が重いと全体が遅くなる。\n *\n * 想定: 一覧を見る 5 / 申請する 3 / 添付を上げる 1 / 承認する 1\n */\nexport function expenseRush(step: ReturnType<typeof buildHttpStep>): Scenario {\n  return {\n    steps: [\n      { name: \"経費一覧\", weight: 5, request: step(\"/api/expenses\") },\n      { name: \"経費申請\", weight: 3, request: step(\"/api/expenses\", { method: \"POST\", body: JSON.stringify({ amount: 1200, category: \"transport\" }) }) },\n      { name: \"添付アップロード\", weight: 1, request: step(\"/api/expenses/attachments\", { method: \"POST\" }) },\n      { name: \"承認\", weight: 1, request: step(\"/api/expenses/approvals/decision\", { method: \"POST\", body: JSON.stringify({ decision: \"approve\" }) }) },\n    ],\n  };\n}\n\n/**\n * 【日中の平常運転】業務時間中の普通のアクセス。\n *\n * **読み取りが大半**。ここが遅いと「システムが重い」と言われる。\n * ランプアップを入れて(rampUpMs: 10_000 等)、徐々に負荷を上げるのが現実的。\n *\n * 想定: ダッシュボード 4 / 各種一覧 4 / 検索 1 / 書き込み 1\n */\nexport function normalDay(step: ReturnType<typeof buildHttpStep>): Scenario {\n  return {\n    steps: [\n      { name: \"ダッシュボード\", weight: 4, request: step(\"/api/dashboard/summary\") },\n      { name: \"請求一覧\", weight: 2, request: step(\"/api/v1/invoices\") },\n      { name: \"勤怠一覧\", weight: 2, request: step(\"/api/attendance\") },\n      { name: \"文書検索(RAG)\", weight: 1, request: step(\"/api/rag/search?q=%E8%A6%8F%E7%A8%8B\", { method: \"GET\" }) },\n      { name: \"経費申請\", weight: 1, request: step(\"/api/expenses\", { method: \"POST\", body: JSON.stringify({ amount: 800 }) }) },\n    ],\n  };\n}\n\n/**\n * 【月次決算】集計処理が走る。件数に比例して重くなる典型。\n *\n * 同時実行数は少ないが**1 本が重い**。タイムアウトしないかを見る。\n * `concurrency: 1〜3` 程度で、`p95` より **max** を見るべきシナリオ。\n */\nexport function monthlyClosing(step: ReturnType<typeof buildHttpStep>): Scenario {\n  return {\n    steps: [\n      { name: \"月次集計\", weight: 3, request: step(\"/api/accounting/closing\", { method: \"POST\", body: JSON.stringify({ month: \"2026-07\" }) }) },\n      { name: \"帳票出力\", weight: 1, request: step(\"/api/reports/monthly\") },\n    ],\n  };\n}\n\n/**\n * 【ヘルスチェックのみ】疎通と最低限の性能確認。\n *\n * 「そもそも繋がるか」「基礎的な応答は何 ms か」を測る。**最初にこれで足場を確認**してから\n * 本番シナリオへ進むと、原因の切り分けが楽になる。\n */\nexport function healthOnly(step: ReturnType<typeof buildHttpStep>): Scenario {\n  return { steps: [{ name: \"health\", request: step(\"/api/health\") }] };\n}\n\n/** 用意しているシナリオの一覧(名前 → 生成関数)。 */\nexport const scenarios = {\n  \"morning-rush\": morningRush,\n  \"expense-rush\": expenseRush,\n  \"normal-day\": normalDay,\n  \"monthly-closing\": monthlyClosing,\n  \"health\": healthOnly,\n} as const;\n\nexport type ScenarioName = keyof typeof scenarios;\n\n/** シナリオごとの推奨設定と、見るべき指標。 */\nexport const scenarioGuide: Record<ScenarioName, { concurrency: number; durationMs: number; rampUpMs: number; watch: string }> = {\n  \"morning-rush\": { concurrency: 200, durationMs: 60_000, rampUpMs: 0, watch: \"エラー率と p99。ロック競合で一部が極端に遅くなる\" },\n  \"expense-rush\": { concurrency: 50, durationMs: 120_000, rampUpMs: 10_000, watch: \"一覧のステップ別 p95。ここが遅いと全体が遅い\" },\n  \"normal-day\": { concurrency: 30, durationMs: 300_000, rampUpMs: 30_000, watch: \"p95 が時間とともに悪化しないか(メモリリーク・接続枯渇)\" },\n  \"monthly-closing\": { concurrency: 2, durationMs: 180_000, rampUpMs: 0, watch: \"max。タイムアウトしないか\" },\n  \"health\": { concurrency: 10, durationMs: 10_000, rampUpMs: 0, watch: \"疎通と基礎レイテンシ\" },\n};\n\n/** ステップ別の結果を人が読める表にする。 */\nexport function formatSteps(steps: { name: string; count: number; success: number; failed: number; latency: { p50: number; p95: number; max: number } }[]): string {\n  const lines = [\"ステップ           件数   成功   失敗   p50    p95    max\"];\n  for (const s of steps) {\n    lines.push(\n      `${s.name.padEnd(18)} ${String(s.count).padStart(5)} ${String(s.success).padStart(6)} ${String(s.failed).padStart(6)} ` +\n        `${`${Math.round(s.latency.p50)}ms`.padStart(6)} ${`${Math.round(s.latency.p95)}ms`.padStart(6)} ${`${Math.round(s.latency.max)}ms`.padStart(6)}`,\n    );\n  }\n  return lines.join(\"\\n\");\n}",
  "notify-channels": "import { type NotifyChannel, type NotifyMessage } from \"@platform/notify\";\nimport { type Mailer } from \"@platform/mail\";\n\n/** メール通知チャネル。level に応じて件名を付ける。 */\nexport function mailChannel(mailer: Mailer, to: string | string[], options: { subjectPrefix?: string } = {}): NotifyChannel {\n  return {\n    async send(message: NotifyMessage) {\n      const prefix = options.subjectPrefix ?? \"通知\";\n      const levelTag = message.level === \"error\" ? \"【重要】\" : message.level === \"warn\" ? \"【注意】\" : \"\";\n      const result = await mailer.sendMail({ to, subject: `${levelTag}${prefix}`, text: message.text });\n      if (!result.ok) throw new Error(\"メール送信に失敗しました\");\n    },\n  };\n}\n\n/** Slack Webhook 通知チャネル。post は fetch などを注入。 */\nexport function slackChannel(\n  webhookUrl: string,\n  post: (url: string, body: { text: string }) => Promise<{ ok: boolean }>,\n): NotifyChannel {\n  return {\n    async send(message: NotifyMessage) {\n      const emoji = message.level === \"error\" ? \":rotating_light: \" : message.level === \"warn\" ? \":warning: \" : \"\";\n      const result = await post(webhookUrl, { text: `${emoji}${message.text}` });\n      if (!result.ok) throw new Error(\"Slack 送信に失敗しました\");\n    },\n  };\n}\n\n/** LINE 通知チャネル。pushText は LINE のプッシュ送信を注入。 */\nexport function lineChannel(\n  to: string,\n  pushText: (to: string, text: string) => Promise<{ ok: boolean }>,\n): NotifyChannel {\n  return {\n    async send(message: NotifyMessage) {\n      const result = await pushText(to, message.text);\n      if (!result.ok) throw new Error(\"LINE 送信に失敗しました\");\n    },\n  };\n}",
  "notify-channels-channels": "import { type NotifyChannel, type NotifyMessage } from \"@platform/notify\";\nimport { type Mailer } from \"@platform/mail\";\n\n/** メール通知チャネル。level に応じて件名を付ける。 */\nexport function mailChannel(mailer: Mailer, to: string | string[], options: { subjectPrefix?: string } = {}): NotifyChannel {\n  return {\n    async send(message: NotifyMessage) {\n      const prefix = options.subjectPrefix ?? \"通知\";\n      const levelTag = message.level === \"error\" ? \"【重要】\" : message.level === \"warn\" ? \"【注意】\" : \"\";\n      const result = await mailer.sendMail({ to, subject: `${levelTag}${prefix}`, text: message.text });\n      if (!result.ok) throw new Error(\"メール送信に失敗しました\");\n    },\n  };\n}\n\n/** Slack Webhook 通知チャネル。post は fetch などを注入。 */\nexport function slackChannel(\n  webhookUrl: string,\n  post: (url: string, body: { text: string }) => Promise<{ ok: boolean }>,\n): NotifyChannel {\n  return {\n    async send(message: NotifyMessage) {\n      const emoji = message.level === \"error\" ? \":rotating_light: \" : message.level === \"warn\" ? \":warning: \" : \"\";\n      const result = await post(webhookUrl, { text: `${emoji}${message.text}` });\n      if (!result.ok) throw new Error(\"Slack 送信に失敗しました\");\n    },\n  };\n}\n\n/** LINE 通知チャネル。pushText は LINE のプッシュ送信を注入。 */\nexport function lineChannel(\n  to: string,\n  pushText: (to: string, text: string) => Promise<{ ok: boolean }>,\n): NotifyChannel {\n  return {\n    async send(message: NotifyMessage) {\n      const result = await pushText(to, message.text);\n      if (!result.ok) throw new Error(\"LINE 送信に失敗しました\");\n    },\n  };\n}",
  "payslip-pdf": "import { buildPayslip, renderPayslipHtml, type PayBreakdown, type PayslipItem } from \"@platform/payroll\";\nimport { createPdf, DEFAULT_INVOICE_PDF_OPTIONS, type PdfRenderer } from \"@platform/pdf\";\n\n/** 給与明細を PDF バイト列にする。renderer はアプリが用意。 */\nexport async function payslipToPdf(\n  breakdown: PayBreakdown,\n  options: { allowances?: PayslipItem[]; deductions?: PayslipItem[]; employeeName?: string; period?: string; companyName?: string },\n  renderer: PdfRenderer,\n) {\n  const payslip = buildPayslip(breakdown, { allowances: options.allowances, deductions: options.deductions });\n  const html = renderPayslipHtml(payslip, { employeeName: options.employeeName, period: options.period, companyName: options.companyName });\n  return createPdf(renderer).fromHtml(html, DEFAULT_INVOICE_PDF_OPTIONS);\n}",
  "payslip-pdf-batch": "import { buildPayslip, renderPayslipHtml, type PayBreakdown, type PayslipItem } from \"@platform/payroll\";\nimport { createPdf, DEFAULT_INVOICE_PDF_OPTIONS, type PdfRenderer } from \"@platform/pdf\";\n\n/** 一括生成の 1 名分の入力。 */\nexport interface PayslipJob {\n  employeeId: string;\n  employeeName: string;\n  breakdown: PayBreakdown;\n  allowances?: PayslipItem[];\n  deductions?: PayslipItem[];\n}\n\n/** 1 名分の生成結果。 */\nexport interface PayslipOutput {\n  employeeId: string;\n  status: \"generated\" | \"failed\";\n  pdf?: Uint8Array;\n  error?: string;\n}\n\n/** 従業員ぶんの給与明細をまとめて PDF 化する。 */\nexport async function generatePayslipBatch(\n  jobs: PayslipJob[],\n  renderer: PdfRenderer,\n  options: { period?: string; companyName?: string } = {},\n): Promise<{ outputs: PayslipOutput[]; summary: { generated: number; failed: number } }> {\n  const service = createPdf(renderer);\n  const outputs: PayslipOutput[] = [];\n\n  for (const job of jobs) {\n    try {\n      const payslip = buildPayslip(job.breakdown, { allowances: job.allowances, deductions: job.deductions });\n      const html = renderPayslipHtml(payslip, { employeeName: job.employeeName, period: options.period, companyName: options.companyName });\n      const result = await service.fromHtml(html, DEFAULT_INVOICE_PDF_OPTIONS);\n      if (result.ok) outputs.push({ employeeId: job.employeeId, status: \"generated\", pdf: result.value });\n      else outputs.push({ employeeId: job.employeeId, status: \"failed\", error: \"PDF 生成に失敗しました\" });\n    } catch (e) {\n      outputs.push({ employeeId: job.employeeId, status: \"failed\", error: e instanceof Error ? e.message : String(e) });\n    }\n  }\n\n  return {\n    outputs,\n    summary: {\n      generated: outputs.filter((o) => o.status === \"generated\").length,\n      failed: outputs.filter((o) => o.status === \"failed\").length,\n    },\n  };\n}",
  "user-table": "\"use client\";\n/**\n * データテーブルの完成テンプレート(外部制御版)。\n * SearchInput(検索)+ Select(絞り込み)+ queryRows(検索/ソート/ページング)+ Pagination を配線し、\n * 検索・フィルタ・並べ替え・ページャを完全に手元で制御する一覧の作り方を示す。\n * (検索/ページング内蔵で済むなら <DataTable searchKeys pageSize /> 単体でも可)\n * @packageDocumentation\n */\nimport * as React from \"react\";\nimport {\n  SearchInput, Select, Pagination, Button, EmptyState, Badge,\n  queryRows, type TableQuery,\n} from \"@platform/ui\";\n\n/** 表示する行(ユーザー)。 */\nexport interface UserRow extends Record<string, unknown> {\n  id: string;\n  name: string;\n  email: string;\n  role: \"admin\" | \"editor\" | \"viewer\";\n  status: \"active\" | \"invited\" | \"suspended\";\n}\n\nconst ROLE_LABELS: Record<UserRow[\"role\"], string> = { admin: \"管理者\", editor: \"編集者\", viewer: \"閲覧者\" };\nconst STATUS_LABELS: Record<UserRow[\"status\"], string> = { active: \"有効\", invited: \"招待中\", suspended: \"停止\" };\nconst PAGE_SIZE = 10;\n\n/** {@link UserTable} の props。 */\nexport interface UserTableProps {\n  users: UserRow[];\n  onExport?: (rows: UserRow[]) => void;\n}\n\n/** 検索 + 役割フィルタ + ソート + ページャ付きのユーザー一覧。 */\nexport function UserTable({ users, onExport }: UserTableProps) {\n  const [search, setSearch] = React.useState(\"\");\n  const [role, setRole] = React.useState<\"all\" | UserRow[\"role\"]>(\"all\");\n  const [sortKey, setSortKey] = React.useState<keyof UserRow>(\"name\");\n  const [sortDir, setSortDir] = React.useState<\"asc\" | \"desc\">(\"asc\");\n  const [page, setPage] = React.useState(1);\n\n  // 1) カスタムフィルタ(役割)→ 2) queryRows(検索/ソート/ページング)\n  const filtered = React.useMemo(() => (role === \"all\" ? users : users.filter((u) => u.role === role)), [users, role]);\n  const query: TableQuery = { search, searchKeys: [\"name\", \"email\"], sortKey: sortKey as string, sortDir, page, pageSize: PAGE_SIZE };\n  const result = React.useMemo(() => queryRows(filtered, query), [filtered, search, sortKey, sortDir, page]);\n\n  // 条件変更でページを先頭に戻す\n  React.useEffect(() => { setPage(1); }, [search, role, sortKey, sortDir]);\n\n  function toggleSort(key: keyof UserRow) {\n    if (sortKey === key) setSortDir((d) => (d === \"asc\" ? \"desc\" : \"asc\"));\n    else { setSortKey(key); setSortDir(\"asc\"); }\n  }\n  const sortMark = (key: keyof UserRow) => (sortKey === key ? (sortDir === \"asc\" ? \" ▲\" : \" ▼\") : \"\");\n\n  return (\n    <div className=\"flex flex-col gap-4\">\n      <div className=\"flex flex-wrap items-center gap-2\">\n        <SearchInput value={search} onChange={setSearch} placeholder=\"名前・メールで検索\" className=\"max-w-xs\" />\n        <Select value={role} onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setRole(e.target.value as typeof role)}>\n          <option value=\"all\">すべての役割</option>\n          <option value=\"admin\">管理者</option>\n          <option value=\"editor\">編集者</option>\n          <option value=\"viewer\">閲覧者</option>\n        </Select>\n        <span className=\"text-sm text-[var(--color-muted)]\">{result.total}件</span>\n        {onExport && <Button variant=\"secondary\" className=\"ml-auto\" onClick={() => onExport(result.rows)}>エクスポート</Button>}\n      </div>\n\n      {result.total === 0 ? (\n        <EmptyState title=\"該当するユーザーがいません\" description=\"検索条件やフィルタを変えてください。\" />\n      ) : (\n        <>\n          <table className=\"w-full border-collapse text-sm\">\n            <thead>\n              <tr className=\"border-b border-[var(--color-border)] text-left text-[var(--color-muted)]\">\n                <th className=\"cursor-pointer py-2 pr-4\" onClick={() => toggleSort(\"name\")}>名前{sortMark(\"name\")}</th>\n                <th className=\"cursor-pointer py-2 pr-4\" onClick={() => toggleSort(\"email\")}>メール{sortMark(\"email\")}</th>\n                <th className=\"py-2 pr-4\">役割</th>\n                <th className=\"py-2\">状態</th>\n              </tr>\n            </thead>\n            <tbody>\n              {result.rows.map((u) => (\n                <tr key={u.id} className=\"border-b border-[var(--color-border)]\">\n                  <td className=\"py-2 pr-4 font-medium text-[var(--color-fg)]\">{u.name}</td>\n                  <td className=\"py-2 pr-4 text-[var(--color-muted)]\">{u.email}</td>\n                  <td className=\"py-2 pr-4\">{ROLE_LABELS[u.role]}</td>\n                  <td className=\"py-2\"><Badge variant={u.status === \"active\" ? \"success\" : u.status === \"suspended\" ? \"danger\" : \"default\"}>{STATUS_LABELS[u.status]}</Badge></td>\n                </tr>\n              ))}\n            </tbody>\n          </table>\n\n          <Pagination page={result.page} totalPages={result.pageCount} onPageChange={setPage} />\n        </>\n      )}\n    </div>\n  );\n}",
  "workplace-ops": "import { summarize, isOverdue, workloadByAssignee, type Task } from \"@platform/task\";\nimport { contractAlerts, summarizeContracts, type Contract } from \"@platform/contract\";\nimport { needsReview, summarizeFaq, type FaqItem } from \"@platform/faq\";\n\n/** 今日やるべきこと 1 件。 */\nexport interface TodoItem {\n  /** どこから来たか。 */\n  source: \"task\" | \"contract\" | \"faq\";\n  /** 深刻度。**放っておくと損をするものほど高い**。 */\n  level: \"danger\" | \"warning\" | \"info\";\n  /** 何が起きているか。 */\n  title: string;\n  /** 何をすべきか。 */\n  action: string;\n  /** 誰の仕事か(分かれば)。 */\n  owner?: string;\n  /** 詳細画面へのリンク。 */\n  href: string;\n}\n\n/** 横断の入力。 */\nexport interface WorkplaceInput {\n  tasks: Task[];\n  contracts: Contract[];\n  faqs: FaqItem[];\n  /** 基準日(テスト注入用)。 */\n  today?: Date;\n}\n\n/**\n * 3 つの領域から「今日やるべきこと」を集めて、**深刻な順**に並べる。\n *\n * 並び順の考え方: **放っておくと損をするもの**が先。\n * 1. 契約の解約予告期限(過ぎると 1 年延びる = お金が出ていく)\n * 2. 期限切れのタスク(約束を破っている)\n * 3. 役に立っていない FAQ(探した人の時間を奪う)\n *\n * @param input タスク・契約・FAQ と基準日\n * @returns 深刻な順のやることリスト\n *\n * @example\n * ```ts\n * for (const todo of buildTodoList({ tasks, contracts, faqs })) {\n *   console.log(`[${todo.level}] ${todo.title} → ${todo.action}`);\n * }\n * ```\n */\nexport function buildTodoList(input: WorkplaceInput): TodoItem[] {\n  const today = input.today ?? new Date();\n  const items: TodoItem[] = [];\n\n  // 1) 契約 — 基盤が判定したアラートをそのまま使う(自作しない)\n  for (const alert of contractAlerts(input.contracts, today)) {\n    items.push({\n      source: \"contract\",\n      level: alert.level,\n      title: `${alert.contract.title}: ${alert.message}`,\n      action: alert.action,\n      ...(alert.contract.owner ? { owner: alert.contract.owner } : {}),\n      href: `/contracts#${alert.contract.id}`,\n    });\n  }\n\n  // 2) タスク — 期限切れだけを拾う(基盤の isOverdue に判定を委ねる)\n  for (const task of input.tasks) {\n    if (!isOverdue(task, today)) continue;\n    items.push({\n      source: \"task\",\n      level: task.priority === \"urgent\" || task.priority === \"high\" ? \"danger\" : \"warning\",\n      title: `${task.title}: 期限(${task.dueDate})を過ぎています`,\n      action: task.assignee ? `${task.assignee} さんに状況を確認してください` : \"担当者を決めてください\",\n      ...(task.assignee ? { owner: task.assignee } : {}),\n      href: `/tasks#${task.id}`,\n    });\n  }\n\n  // 3) FAQ — 要見直しを拾う(基盤の needsReview に判定を委ねる)\n  for (const { item, reason } of needsReview(input.faqs)) {\n    items.push({\n      source: \"faq\",\n      level: \"info\",\n      title: `FAQ「${item.question}」: ${reason}`,\n      action: \"内容を見直すか、アーカイブしてください\",\n      href: `/faq#${item.id}`,\n    });\n  }\n\n  const order: Record<TodoItem[\"level\"], number> = { danger: 0, warning: 1, info: 2 };\n  const sourceOrder: Record<TodoItem[\"source\"], number> = { contract: 0, task: 1, faq: 2 };\n  return items.sort(\n    (a, b) => order[a.level] - order[b.level] || sourceOrder[a.source] - sourceOrder[b.source],\n  );\n}\n\n/** 朝に見る要約。 */\nexport interface MorningSummary {\n  /** 今日やるべきことの件数。 */\n  todoCount: number;\n  /** そのうち「至急」。 */\n  urgentCount: number;\n  /** タスクの進捗(0–1)。 */\n  taskProgress: number;\n  /** 期限切れタスクの数。 */\n  overdueTasks: number;\n  /** 有効な契約の年間金額。 */\n  contractAmount: number;\n  /** FAQ の役に立った率(投票が無ければ undefined)。 */\n  faqHelpfulRate: number | undefined;\n  /** 最も負荷の高い担当者(未完タスクの工数順)。 */\n  busiestPerson: { assignee: string; count: number; hours: number } | undefined;\n}\n\n/**\n * 朝に見る 1 画面分の要約を作る。\n *\n * **各領域の集計は基盤に任せ、ここは束ねるだけ**(集計ロジックを再実装しない)。\n *\n * @param input タスク・契約・FAQ と基準日\n * @returns 要約\n */\nexport function morningSummary(input: WorkplaceInput): MorningSummary {\n  const today = input.today ?? new Date();\n  const todos = buildTodoList(input);\n  const taskStats = summarize(input.tasks, today);\n  const contractStats = summarizeContracts(input.contracts, today);\n  const faqStats = summarizeFaq(input.faqs);\n  const workload = workloadByAssignee(input.tasks);\n\n  return {\n    todoCount: todos.length,\n    urgentCount: todos.filter((t) => t.level === \"danger\").length,\n    taskProgress: taskStats.rate,\n    overdueTasks: taskStats.overdue,\n    contractAmount: contractStats.activeAmount,\n    faqHelpfulRate: faqStats.helpfulRate,\n    busiestPerson: workload[0],\n  };\n}\n\n/**\n * 担当者ごとに「その人がやるべきこと」をまとめる。\n *\n * 朝会で「今日は誰が何をするか」を確認するのに使う。\n * **担当者が決まっていないものは `(未割り当て)`** に入れる(放置されがちなので目立たせる)。\n *\n * @param todos {@link buildTodoList} の結果\n * @returns 担当者ごとのやることリスト(件数の多い順)\n */\nexport function groupByOwner(todos: TodoItem[]): { owner: string; items: TodoItem[] }[] {\n  const map = new Map<string, TodoItem[]>();\n  for (const t of todos) {\n    const key = t.owner ?? \"(未割り当て)\";\n    const list = map.get(key) ?? [];\n    list.push(t);\n    map.set(key, list);\n  }\n  return [...map.entries()]\n    .map(([owner, items]) => ({ owner, items }))\n    .sort((a, b) => b.items.length - a.items.length);\n}\n\n/** 人が読める形に整形する(朝会のメモ・Slack 通知に使う)。 */\nexport function formatTodoList(todos: TodoItem[]): string {\n  if (todos.length === 0) return \"今日やるべきことはありません。\";\n  const mark: Record<TodoItem[\"level\"], string> = { danger: \"🔴\", warning: \"🟡\", info: \"⚪\" };\n  return todos.map((t) => `${mark[t.level]} ${t.title}\\n   → ${t.action}${t.owner ? `(${t.owner})` : \"\"}`).join(\"\\n\");\n}",
};
